"""
Plot reliability diagrams for each UQ method.

Consumes: results/uq_predictions.csv (generated by T016/T022b)
Outputs: results/reliability_<method>.pdf and results/reliability_<method>.png
"""
import os
import numpy as np
import pandas as pd
import matplotlib.pyplot as plt
from typing import List, Dict, Any

# Ensure results directory exists
RESULTS_DIR = "results"
os.makedirs(RESULTS_DIR, exist_ok=True)

def load_predictions() -> pd.DataFrame:
    """Load the UQ predictions CSV generated by the pipeline."""
    path = os.path.join(RESULTS_DIR, "uq_predictions.csv")
    if not os.path.exists(path):
        raise FileNotFoundError(
            f"Input file not found: {path}. "
            "Please ensure T016/T022b has run successfully."
        )
    return pd.read_csv(path)

def calculate_calibration_bins(
    df: pd.DataFrame,
    n_bins: int = 10
) -> Dict[str, Any]:
    """
    Calculate binned calibration metrics for a single method.
    
    Returns dict with:
      - bin_centers: midpoints of bins
      - empirical_freq: observed fraction of correct predictions per bin
      - predicted_conf: average predicted confidence per bin
      - bin_sizes: number of samples in each bin
    """
    # Ensure we have variance and prediction columns
    # We assume the DataFrame has: method, prediction, variance, lower_90, upper_90, target (true value)
    # Note: 'target' column must exist in uq_predictions.csv (added by T016/T022b)
    
    if 'target' not in df.columns:
        raise ValueError("DataFrame must contain 'target' column for calibration.")
    
    # Calculate if the true value falls within the 90% prediction interval
    # Assuming lower_90 and upper_90 are the 5th and 95th percentiles
    df = df.copy()
    df['in_interval'] = (df['target'] >= df['lower_90']) & (df['target'] <= df['upper_90'])
    
    # Define confidence levels (e.g., 90% interval corresponds to 0.9 confidence)
    # We will bin by predicted confidence. For simplicity, we use the width of the interval
    # as a proxy for confidence (narrower interval = higher confidence).
    # Alternatively, if the model outputs a direct confidence score, we could use that.
    # Here, we bin by the normalized interval width relative to the data range.
    
    # Calculate interval width
    df['interval_width'] = df['upper_90'] - df['lower_90']
    
    # Normalize interval width to [0, 1] (inverse: smaller width = higher confidence)
    max_width = df['interval_width'].max()
    if max_width == 0:
        max_width = 1.0 # Avoid division by zero
    df['confidence'] = 1.0 - (df['interval_width'] / max_width)
    
    # Bin the confidence scores
    df['bin'] = pd.cut(df['confidence'], bins=n_bins, labels=False, include_lowest=True)
    
    # Calculate metrics per bin
    bin_stats = df.groupby('bin').agg(
        predicted_conf=('confidence', 'mean'),
        empirical_freq=('in_interval', 'mean'),
        bin_sizes=('in_interval', 'size')
    ).reset_index()
    
    # Calculate bin centers for plotting
    bin_edges = np.linspace(0, 1, n_bins + 1)
    bin_centers = (bin_edges[:-1] + bin_edges[1:]) / 2
    
    return {
        'bin_centers': bin_centers,
        'predicted_conf': bin_stats['predicted_conf'].values,
        'empirical_freq': bin_stats['empirical_freq'].values,
        'bin_sizes': bin_stats['bin_sizes'].values
    }

def plot_reliability_diagram(
    stats: Dict[str, Any],
    method_name: str,
    output_path_pdf: str,
    output_path_png: str,
    n_bins: int = 10
) -> None:
    """
    Generate and save the reliability diagram.
    """
    fig, ax = plt.subplots(figsize=(8, 6))
    
    # Plot the ideal calibration line
    ax.plot([0, 1], [0, 1], 'k--', label='Ideal Calibration')
    
    # Plot the actual calibration curve
    ax.bar(
        stats['bin_centers'],
        stats['empirical_freq'],
        width=1.0/n_bins,
        alpha=0.7,
        label='Actual',
        color='steelblue',
        edgecolor='black'
    )
    
    # Plot error bars if we have bin sizes (optional, but good for visualization)
    # For simplicity, we just plot the bars.
    
    ax.set_xlabel('Predicted Confidence')
    ax.set_ylabel('Empirical Frequency (Fraction in Interval)')
    ax.set_title(f'Reliability Diagram: {method_name}')
    ax.legend(loc='upper left')
    ax.set_xlim(0, 1)
    ax.set_ylim(0, 1)
    ax.grid(True, alpha=0.3)
    
    # Save to PDF
    plt.tight_layout()
    plt.savefig(output_path_pdf, format='pdf')
    
    # Save to PNG
    plt.savefig(output_path_png, format='png', dpi=150)
    
    plt.close(fig)

def main():
    """
    Main entry point to generate reliability diagrams for all methods.
    """
    print("Loading predictions...")
    df = load_predictions()
    
    # Check required columns
    required_cols = ['method', 'lower_90', 'upper_90', 'target']
    missing = [col for col in required_cols if col not in df.columns]
    if missing:
        raise ValueError(f"Missing required columns in input: {missing}")
    
    methods = df['method'].unique()
    print(f"Found methods: {methods}")
    
    for method in methods:
        print(f"Processing method: {method}")
        method_df = df[df['method'] == method].copy()
        
        if len(method_df) == 0:
            print(f"  No data for method {method}, skipping.")
            continue
        
        # Calculate bin statistics
        stats = calculate_calibration_bins(method_df)
        
        # Define output paths
        safe_method = method.replace(" ", "_").replace("/", "_")
        base_name = f"reliability_{safe_method}"
        pdf_path = os.path.join(RESULTS_DIR, f"{base_name}.pdf")
        png_path = os.path.join(RESULTS_DIR, f"{base_name}.png")
        
        # Generate plot
        plot_reliability_diagram(
            stats=stats,
            method_name=method,
            output_path_pdf=pdf_path,
            output_path_png=png_path
        )
        
        print(f"  Saved: {pdf_path}")
        print(f"  Saved: {png_path}")
    
    print("Reliability diagrams generation complete.")

if __name__ == "__main__":
    main()